item.description:
 &lt;blockquote&gt;
&lt;p&gt;&lt;code&gt;Boost&lt;/code&gt; 是一个开源的 C++ 库集合，提供了许多实用的功能，如网络编程、图形界面、数学计算等。Boost 库可以与标准 C++ 库无缝集成，扩展了 C++ 的功能。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h1 id=&#34;安装-boost-库&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#安装-boost-库&#34;&gt;&lt;/a&gt; 安装 Boost 库&lt;/h1&gt;
&lt;p&gt;通过 APT 包管理器安装 Boost 库：&lt;/p&gt;
&lt;pre class=&#34;highlight&#34;&gt;&lt;code class=&#34;shell&#34;&gt;&lt;span class=&#34;hljs-meta prompt_&#34;&gt;# &lt;/span&gt;&lt;span class=&#34;language-bash&#34;&gt;1. 更新软件包索引&lt;/span&gt;
sudo apt update
&lt;span class=&#34;hljs-meta prompt_&#34;&gt;
# &lt;/span&gt;&lt;span class=&#34;language-bash&#34;&gt;2. 安装 Boost 核心库和开发文件（包含头文件和静态/动态库）&lt;/span&gt;
sudo apt install libboost-all-dev -y
&lt;span class=&#34;hljs-meta prompt_&#34;&gt;
# &lt;/span&gt;&lt;span class=&#34;language-bash&#34;&gt;3. 验证安装（检查版本）&lt;/span&gt;
boostversion=$(cat /usr/include/boost/version.hpp | grep &amp;quot;#define BOOST_VERSION&amp;quot; | awk &amp;#x27;&amp;#123;print $3&amp;#125;&amp;#x27;)

echo &amp;quot;Boost 版本: $boostversion&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;h1 id=&#34;基本使用&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#基本使用&#34;&gt;&lt;/a&gt; 基本使用&lt;/h1&gt;
&lt;p&gt;同步操作会阻塞当前线程，直到操作完成。异步操作则不会阻塞线程，通过回调函数在操作完成后触发。&lt;/p&gt;
&lt;h2 id=&#34;同步&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#同步&#34;&gt;&lt;/a&gt; 同步&lt;/h2&gt;
&lt;pre class=&#34;highlight&#34;&gt;&lt;code class=&#34;cpp&#34;&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;iostream&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt;&lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;boost/asio.hpp&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;&amp;#123;
    boost::asio::io_context io;
    boost::&lt;span class=&#34;hljs-function&#34;&gt;asio::steady_timer &lt;span class=&#34;hljs-title&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(io, boost::asio::chrono::seconds(&lt;span class=&#34;hljs-number&#34;&gt;5&lt;/span&gt;))&lt;/span&gt;&lt;/span&gt;;
    &lt;span class=&#34;hljs-comment&#34;&gt;// 同步,阻塞线程5秒&lt;/span&gt;
    t.&lt;span class=&#34;hljs-built_in&#34;&gt;wait&lt;/span&gt;();
    &lt;span class=&#34;hljs-comment&#34;&gt;// wait() 返回，定时器资源（如系统句柄）被自动释放&lt;/span&gt;
    std::cout&amp;lt;&amp;lt;&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;Hello,world!&amp;quot;&lt;/span&gt;&amp;lt;&amp;lt;std::endl;
    &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;定时器&lt;/strong&gt;&lt;br /&gt;
&lt;code&gt;steady_timer&lt;/code&gt; 是 &lt;code&gt;Boost.Asio&lt;/code&gt; 提供的定时器类，用于在指定时间后执行回调函数。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;steady_timer &lt;/code&gt;的构造函数需要 &lt;code&gt;io_context&lt;/code&gt; 参数，目的是 &lt;strong&gt;​显式声明&lt;/strong&gt; 该定时器依赖** 的&lt;strong&gt;事件循环&lt;/strong&gt;。这种设计确保类型安全，避免隐式关联导致的错误。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;io_context 的作用&lt;/strong&gt;&lt;br /&gt;
&lt;code&gt;io_context&lt;/code&gt; 是 &lt;code&gt;Boost.Asio&lt;/code&gt; 的核心组件，负责调度以及执行所有异步（如 DNS 解析、连接、读写）和同步操作的生命周期。（如定时器、网络 I/O）。&lt;/p&gt;
&lt;h2 id=&#34;异步&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#异步&#34;&gt;&lt;/a&gt; 异步&lt;/h2&gt;
&lt;p&gt;异步操作需要事件循环来驱动，&lt;code&gt;io_context::run()&lt;/code&gt; 方法启动事件处理流程。&lt;/p&gt;
&lt;pre class=&#34;highlight&#34;&gt;&lt;code class=&#34;cpp&#34;&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;iostream&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt;&lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;boost/asio.hpp&amp;gt;&lt;/span&gt;&lt;/span&gt;

&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(&lt;span class=&#34;hljs-type&#34;&gt;const&lt;/span&gt; boost::system::error_code&amp;amp; a &lt;span class=&#34;hljs-comment&#34;&gt;/*e*/&lt;/span&gt;)&lt;/span&gt;
&lt;/span&gt;&amp;#123;
    std::cout&amp;lt;&amp;lt;a&amp;lt;&amp;lt;std::endl;
    std::cout&amp;lt;&amp;lt;&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;Hello,world!&amp;quot;&lt;/span&gt;&amp;lt;&amp;lt;std::endl;
&amp;#125;
&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;&amp;#123;
    boost::asio::io_context io;
    boost::&lt;span class=&#34;hljs-function&#34;&gt;asio::steady_timer &lt;span class=&#34;hljs-title&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(io, boost::asio::chrono::seconds(&lt;span class=&#34;hljs-number&#34;&gt;5&lt;/span&gt;))&lt;/span&gt;&lt;/span&gt;; 
    t.&lt;span class=&#34;hljs-built_in&#34;&gt;async_wait&lt;/span&gt;(&amp;amp;print);   &lt;span class=&#34;hljs-comment&#34;&gt;// 异步,不会阻塞线程，回调函数print会在5秒后执行&lt;/span&gt;
    io.&lt;span class=&#34;hljs-built_in&#34;&gt;run&lt;/span&gt;();
    &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;io.run() &lt;/code&gt;是异步编程的核心，负责监听操作系统异步操作（如定时器到期、网络请求完成）的完成事件，确保资源（如&lt;code&gt;定时器&lt;/code&gt;、&lt;code&gt;socket&lt;/code&gt;）被正确释放，并触发回调函数。&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;特性&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;同步代码&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;异步代码&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​执行方式&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;阻塞等待（&lt;code&gt;wait()&lt;/code&gt;）&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;非阻塞，通过回调触发&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​事件循环&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;无需 &lt;code&gt;io.run()&lt;/code&gt;&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;必须调用 &lt;code&gt;io.run()&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​线程占用&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;单线程阻塞&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;单线程/多线程（由 &lt;code&gt;run()&lt;/code&gt; 决定）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​适用场景&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;简单、短耗时操作&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;高并发、实时性要求高的场景&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;hr /&gt;
&lt;p&gt;&lt;strong&gt;​时间点计算&lt;/strong&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;strong&gt;函数式编程&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre class=&#34;highlight&#34;&gt;&lt;code class=&#34;cpp&#34;&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;functional&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;iostream&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;boost/asio.hpp&amp;gt;&lt;/span&gt;&lt;/span&gt;

&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(&lt;span class=&#34;hljs-type&#34;&gt;const&lt;/span&gt; boost::system::error_code&amp;amp; &lt;span class=&#34;hljs-comment&#34;&gt;/*e*/&lt;/span&gt;,
    boost::asio::steady_timer* t, &lt;span class=&#34;hljs-type&#34;&gt;int&lt;/span&gt;* count)&lt;/span&gt;
&lt;/span&gt;&amp;#123;
  &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; (*count &amp;lt; &lt;span class=&#34;hljs-number&#34;&gt;5&lt;/span&gt;)
  &amp;#123;
    std::cout &amp;lt;&amp;lt; *count &amp;lt;&amp;lt; std::endl;
    ++(*count);

    &lt;span class=&#34;hljs-comment&#34;&gt;// 新到期时间 = 当前到期时间 + 1秒&lt;/span&gt;
    t-&amp;gt;&lt;span class=&#34;hljs-built_in&#34;&gt;expires_at&lt;/span&gt;(t-&amp;gt;&lt;span class=&#34;hljs-built_in&#34;&gt;expiry&lt;/span&gt;() + boost::asio::chrono::&lt;span class=&#34;hljs-built_in&#34;&gt;seconds&lt;/span&gt;(&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;));

    &lt;span class=&#34;hljs-comment&#34;&gt;// 异步等待新到期时间&lt;/span&gt;
    t-&amp;gt;&lt;span class=&#34;hljs-built_in&#34;&gt;async_wait&lt;/span&gt;(std::&lt;span class=&#34;hljs-built_in&#34;&gt;bind&lt;/span&gt;(print,
        std::placeholders::_1, t, count));
  &amp;#125;
&amp;#125;

&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt;
&lt;/span&gt;&amp;#123;
  boost::asio::io_context io;

  &lt;span class=&#34;hljs-type&#34;&gt;int&lt;/span&gt; count = &lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;;
  boost::&lt;span class=&#34;hljs-function&#34;&gt;asio::steady_timer &lt;span class=&#34;hljs-title&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(io, boost::asio::chrono::seconds(&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;))&lt;/span&gt;&lt;/span&gt;;

  t.&lt;span class=&#34;hljs-built_in&#34;&gt;async_wait&lt;/span&gt;(std::&lt;span class=&#34;hljs-built_in&#34;&gt;bind&lt;/span&gt;(print,
    std::placeholders::_1, &amp;amp;t, &amp;amp;count));

  io.&lt;span class=&#34;hljs-built_in&#34;&gt;run&lt;/span&gt;();

  std::cout &amp;lt;&amp;lt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;Final count is &amp;quot;&lt;/span&gt; &amp;lt;&amp;lt; count &amp;lt;&amp;lt; std::endl;

  &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;;
&amp;#125;

&lt;span class=&#34;hljs-comment&#34;&gt;// 输出&lt;/span&gt;
&lt;span class=&#34;hljs-comment&#34;&gt;// 0&lt;/span&gt;
&lt;span class=&#34;hljs-comment&#34;&gt;// 1&lt;/span&gt;
&lt;span class=&#34;hljs-comment&#34;&gt;// 2&lt;/span&gt;
&lt;span class=&#34;hljs-comment&#34;&gt;// 3&lt;/span&gt;
&lt;span class=&#34;hljs-comment&#34;&gt;// 4&lt;/span&gt;
&lt;span class=&#34;hljs-comment&#34;&gt;// Final count is 5&lt;/span&gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;pre class=&#34;highlight&#34;&gt;&lt;code class=&#34;cpp&#34;&gt;&lt;span class=&#34;hljs-comment&#34;&gt;// 新到期时间 = 当前到期时间 + 1秒&lt;/span&gt;
t-&amp;gt;&lt;span class=&#34;hljs-built_in&#34;&gt;expires_at&lt;/span&gt;(t-&amp;gt;&lt;span class=&#34;hljs-built_in&#34;&gt;expires_at&lt;/span&gt;() + boost::asio::chrono::&lt;span class=&#34;hljs-built_in&#34;&gt;seconds&lt;/span&gt;(&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;));
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;t-&amp;gt;expires_at()&lt;/code&gt; 返回定时器当前的到期时间点（&lt;code&gt;system_clock::time_point&lt;/code&gt; 类型），&lt;code&gt;boost::asio::chrono::seconds(1)&lt;/code&gt;表示一个 ​时间间隔​（&lt;code&gt;duration&lt;/code&gt; 类型）。两者相加会生成新的到期时间点：&lt;/p&gt;
&lt;p&gt;这种设计允许动态调整定时器的触发时间，适用于需要重复执行任务的场景（如每隔&lt;code&gt;1&lt;/code&gt;秒打印一次计数器）。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;​类型匹配的底层原理&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;code&gt;expires_at()&lt;/code&gt; 的参数类型是 &lt;code&gt;system_clock::time_point&lt;/code&gt;，而 &lt;code&gt;boost::asio::chrono::seconds(1)&lt;/code&gt; 的类型是 &lt;code&gt;duration&lt;/code&gt;,明确指定了时间单位（秒），避免了因隐式类型转换导致的单位混淆（如误用毫秒或微秒）。&lt;br /&gt;
&lt;code&gt;Boost.Asio&lt;/code&gt; 的 &lt;code&gt;chrono&lt;/code&gt; 库通过 &lt;strong&gt;​类型推导&lt;/strong&gt; 和 &lt;strong&gt;运算符重载&lt;/strong&gt;，自动将 &lt;code&gt;duration&lt;/code&gt; 转换为 &lt;code&gt;time_point&lt;/code&gt;，确保表达式合法。&lt;br /&gt;
若直接使用 &lt;code&gt;t-&amp;gt;expires_at(1)&lt;/code&gt;，编译器会报错，因为 &lt;code&gt;1&lt;/code&gt; 的类型是 &lt;code&gt;int&lt;/code&gt;，无法隐式转换为 &lt;code&gt;time_point&lt;/code&gt;。&lt;/p&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;&lt;strong&gt;面向对象编程&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre class=&#34;highlight&#34;&gt;&lt;code class=&#34;cpp&#34;&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;functional&amp;gt;&lt;/span&gt; &lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;iostream&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;boost/asio.hpp&amp;gt;&lt;/span&gt;&lt;/span&gt;

&lt;span class=&#34;hljs-keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;hljs-title class_&#34;&gt;printer&lt;/span&gt;
&amp;#123;
&lt;span class=&#34;hljs-keyword&#34;&gt;public&lt;/span&gt;:
    &lt;span class=&#34;hljs-comment&#34;&gt;// 构造函数，初始化timer_成员和count_成员&lt;/span&gt;
    &lt;span class=&#34;hljs-built_in&#34;&gt;printer&lt;/span&gt;(boost::asio::io_context&amp;amp; io)
    : &lt;span class=&#34;hljs-built_in&#34;&gt;timer_&lt;/span&gt;(io, boost::asio::chrono::&lt;span class=&#34;hljs-built_in&#34;&gt;seconds&lt;/span&gt;(&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;)),  &lt;span class=&#34;hljs-comment&#34;&gt;// 初始化timer_成员&lt;/span&gt;
      &lt;span class=&#34;hljs-built_in&#34;&gt;count_&lt;/span&gt;(&lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;)                                     &lt;span class=&#34;hljs-comment&#34;&gt;// 初始化count_成员&lt;/span&gt;
    &amp;#123;
    &lt;span class=&#34;hljs-comment&#34;&gt;// bind() 函数将成员函数print绑定到当前对象上，并作为回调函数传递给timer_.async_wait()&lt;/span&gt;
        timer_.&lt;span class=&#34;hljs-built_in&#34;&gt;async_wait&lt;/span&gt;(std::&lt;span class=&#34;hljs-built_in&#34;&gt;bind&lt;/span&gt;(&amp;amp;printer::print, &lt;span class=&#34;hljs-keyword&#34;&gt;this&lt;/span&gt;)); 
    &amp;#125;
    &lt;span class=&#34;hljs-comment&#34;&gt;// 析构函数&lt;/span&gt;
    ~&lt;span class=&#34;hljs-built_in&#34;&gt;printer&lt;/span&gt;()
    &amp;#123;
        std::cout&amp;lt;&amp;lt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;final count is &amp;quot;&lt;/span&gt;&amp;lt;&amp;lt; count_ &amp;lt;&amp;lt;std::endl;
    &amp;#125;

    &lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;&amp;#123;
        &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt;(count_&amp;lt;&lt;span class=&#34;hljs-number&#34;&gt;5&lt;/span&gt;)
        &amp;#123;
            std::cout &amp;lt;&amp;lt; count_ &amp;lt;&amp;lt;std::endl;
            ++count_;
            &lt;span class=&#34;hljs-comment&#34;&gt;// 新到期时间 = 当前到期时间 + 1秒&lt;/span&gt;
            timer_.&lt;span class=&#34;hljs-built_in&#34;&gt;expires_at&lt;/span&gt;(timer_.&lt;span class=&#34;hljs-built_in&#34;&gt;expiry&lt;/span&gt;() + boost::asio::chrono::&lt;span class=&#34;hljs-built_in&#34;&gt;seconds&lt;/span&gt;(&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;));
            timer_.&lt;span class=&#34;hljs-built_in&#34;&gt;async_wait&lt;/span&gt;(std::&lt;span class=&#34;hljs-built_in&#34;&gt;bind&lt;/span&gt;(&amp;amp;printer::print,&lt;span class=&#34;hljs-keyword&#34;&gt;this&lt;/span&gt;));
        &amp;#125;
    &amp;#125;

&lt;span class=&#34;hljs-keyword&#34;&gt;private&lt;/span&gt;:
    boost::asio::steady_timer timer_;
    &lt;span class=&#34;hljs-type&#34;&gt;int&lt;/span&gt; count_;
&amp;#125;;

&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt;
&lt;/span&gt;&amp;#123;
  boost::asio::io_context io;
  &lt;span class=&#34;hljs-function&#34;&gt;printer &lt;span class=&#34;hljs-title&#34;&gt;p&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(io)&lt;/span&gt;&lt;/span&gt;;
  io.&lt;span class=&#34;hljs-built_in&#34;&gt;run&lt;/span&gt;();
  &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;;
&amp;#125;

&lt;span class=&#34;hljs-comment&#34;&gt;// 输出&lt;/span&gt;
&lt;span class=&#34;hljs-comment&#34;&gt;// 0&lt;/span&gt;
&lt;span class=&#34;hljs-comment&#34;&gt;// 1&lt;/span&gt;
&lt;span class=&#34;hljs-comment&#34;&gt;// 2&lt;/span&gt;
&lt;span class=&#34;hljs-comment&#34;&gt;// 3&lt;/span&gt;
&lt;span class=&#34;hljs-comment&#34;&gt;// 4&lt;/span&gt;
&lt;span class=&#34;hljs-comment&#34;&gt;// final count is 5&lt;/span&gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;优缺点对比&lt;/strong&gt;&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;维度&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;​函数式&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;​面向对象&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​代码简洁性&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;✅ 代码简短，适合简单场景&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;❌ 类定义增加代码量&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​安全性&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;❌ 需手动管理指针，易出错&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;✅ 自动管理资源，避免悬垂指针&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​扩展性&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;❌ 修改需调整参数传递链&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;✅ 新增功能只需扩展类方法&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​异步上下文&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;❌ 依赖外部变量，多线程下可能竞争&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;✅ 成员变量天然隔离，适合多线程异步任务&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;​性能开销&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;✅ 无虚函数或类结构开销&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;❌ 类实例化带来微小内存开销&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;hr /&gt;
&lt;p&gt;&lt;strong&gt;线程安全的异步任务队列（通过 Strand 串行化）&lt;/strong&gt;&lt;/p&gt;
&lt;pre class=&#34;highlight&#34;&gt;&lt;code class=&#34;cpp&#34;&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;functional&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;iostream&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;thread&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;boost/asio.hpp&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-comment&#34;&gt;// 通过 strand_ 序列化回调函数的执行&lt;/span&gt;
&lt;span class=&#34;hljs-keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;hljs-title class_&#34;&gt;printer&lt;/span&gt;
&amp;#123;
&lt;span class=&#34;hljs-keyword&#34;&gt;public&lt;/span&gt;:
    &lt;span class=&#34;hljs-built_in&#34;&gt;printer&lt;/span&gt;(boost::asio::io_context&amp;amp; io)
        : &lt;span class=&#34;hljs-built_in&#34;&gt;strand_&lt;/span&gt;(boost::asio::&lt;span class=&#34;hljs-built_in&#34;&gt;make_strand&lt;/span&gt;(io)),     &lt;span class=&#34;hljs-comment&#34;&gt;// 初始化strand_成员&lt;/span&gt;
        &lt;span class=&#34;hljs-built_in&#34;&gt;timer1_&lt;/span&gt;(io, boost::asio::chrono::&lt;span class=&#34;hljs-built_in&#34;&gt;seconds&lt;/span&gt;(&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;)),&lt;span class=&#34;hljs-comment&#34;&gt;// 初始化timer1_成员&lt;/span&gt;
        &lt;span class=&#34;hljs-built_in&#34;&gt;timer2_&lt;/span&gt;(io, boost::asio::chrono::&lt;span class=&#34;hljs-built_in&#34;&gt;seconds&lt;/span&gt;(&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;)),&lt;span class=&#34;hljs-comment&#34;&gt;// 初始化timer2_成员&lt;/span&gt;
        &lt;span class=&#34;hljs-built_in&#34;&gt;count_&lt;/span&gt;(&lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;)
    &amp;#123;
        &lt;span class=&#34;hljs-comment&#34;&gt;// 使用strand_串行化异步操作,bind_executor()将异步操作绑定到strand_上&lt;/span&gt;
        timer1_.&lt;span class=&#34;hljs-built_in&#34;&gt;async_wait&lt;/span&gt;(boost::asio::&lt;span class=&#34;hljs-built_in&#34;&gt;bind_executor&lt;/span&gt;(strand_,
            std::&lt;span class=&#34;hljs-built_in&#34;&gt;bind&lt;/span&gt;(&amp;amp;printer::print1, &lt;span class=&#34;hljs-keyword&#34;&gt;this&lt;/span&gt;)));

        timer2_.&lt;span class=&#34;hljs-built_in&#34;&gt;async_wait&lt;/span&gt;(boost::asio::&lt;span class=&#34;hljs-built_in&#34;&gt;bind_executor&lt;/span&gt;(strand_,
            std::&lt;span class=&#34;hljs-built_in&#34;&gt;bind&lt;/span&gt;(&amp;amp;printer::print2, &lt;span class=&#34;hljs-keyword&#34;&gt;this&lt;/span&gt;)));
    &amp;#125;

    ~&lt;span class=&#34;hljs-built_in&#34;&gt;printer&lt;/span&gt;()
    &amp;#123;
      std::cout &amp;lt;&amp;lt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;Final count is &amp;quot;&lt;/span&gt; &amp;lt;&amp;lt; count_ &amp;lt;&amp;lt; std::endl;
    &amp;#125;
    &lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;print1&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt;
    &lt;/span&gt;&amp;#123;
        &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; (count_ &amp;lt; &lt;span class=&#34;hljs-number&#34;&gt;10&lt;/span&gt;)
        &amp;#123;
        std::cout &amp;lt;&amp;lt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;Timer 1: &amp;quot;&lt;/span&gt; &amp;lt;&amp;lt; count_ &amp;lt;&amp;lt; std::endl;
        ++count_;

        timer1_.&lt;span class=&#34;hljs-built_in&#34;&gt;expires_at&lt;/span&gt;(timer1_.&lt;span class=&#34;hljs-built_in&#34;&gt;expiry&lt;/span&gt;() + boost::asio::chrono::&lt;span class=&#34;hljs-built_in&#34;&gt;seconds&lt;/span&gt;(&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;));

        timer1_.&lt;span class=&#34;hljs-built_in&#34;&gt;async_wait&lt;/span&gt;(boost::asio::&lt;span class=&#34;hljs-built_in&#34;&gt;bind_executor&lt;/span&gt;(strand_,
                std::&lt;span class=&#34;hljs-built_in&#34;&gt;bind&lt;/span&gt;(&amp;amp;printer::print1, &lt;span class=&#34;hljs-keyword&#34;&gt;this&lt;/span&gt;)));
        &amp;#125;
    &amp;#125;

    &lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;print2&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt;
    &lt;/span&gt;&amp;#123;
        &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; (count_ &amp;lt; &lt;span class=&#34;hljs-number&#34;&gt;10&lt;/span&gt;)
        &amp;#123;
        std::cout &amp;lt;&amp;lt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;Timer 2: &amp;quot;&lt;/span&gt; &amp;lt;&amp;lt; count_ &amp;lt;&amp;lt; std::endl;
        ++count_;

        timer2_.&lt;span class=&#34;hljs-built_in&#34;&gt;expires_at&lt;/span&gt;(timer2_.&lt;span class=&#34;hljs-built_in&#34;&gt;expiry&lt;/span&gt;() + boost::asio::chrono::&lt;span class=&#34;hljs-built_in&#34;&gt;seconds&lt;/span&gt;(&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;));

        timer2_.&lt;span class=&#34;hljs-built_in&#34;&gt;async_wait&lt;/span&gt;(boost::asio::&lt;span class=&#34;hljs-built_in&#34;&gt;bind_executor&lt;/span&gt;(strand_,
                std::&lt;span class=&#34;hljs-built_in&#34;&gt;bind&lt;/span&gt;(&amp;amp;printer::print2, &lt;span class=&#34;hljs-keyword&#34;&gt;this&lt;/span&gt;)));
        &amp;#125;
    &amp;#125;

&lt;span class=&#34;hljs-keyword&#34;&gt;private&lt;/span&gt;:
  boost::asio::strand&amp;lt;boost::asio::io_context::executor_type&amp;gt; strand_;
  boost::asio::steady_timer timer1_;
  boost::asio::steady_timer timer2_;
  &lt;span class=&#34;hljs-type&#34;&gt;int&lt;/span&gt; count_;
&amp;#125;;

&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt;
&lt;/span&gt;&amp;#123;
  boost::asio::io_context io;
  &lt;span class=&#34;hljs-function&#34;&gt;printer &lt;span class=&#34;hljs-title&#34;&gt;p&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(io)&lt;/span&gt;&lt;/span&gt;;
  &lt;span class=&#34;hljs-comment&#34;&gt;// 创建一个新线程，执行 Lambda 表达式中的代码 (即 io.run())&lt;/span&gt;
  &lt;span class=&#34;hljs-function&#34;&gt;std::thread &lt;span class=&#34;hljs-title&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;([&amp;amp;]&amp;#123; io.run(); &amp;#125;)&lt;/span&gt;&lt;/span&gt;;
  io.&lt;span class=&#34;hljs-built_in&#34;&gt;run&lt;/span&gt;();
  &lt;span class=&#34;hljs-comment&#34;&gt;// 阻塞主线程，直到 t 线程结束&lt;/span&gt;
  t.&lt;span class=&#34;hljs-built_in&#34;&gt;join&lt;/span&gt;();

  &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;代码通过多线程运行 &lt;code&gt;io_context &lt;/code&gt;的事件循环，结合 &lt;code&gt;strand_&lt;/code&gt; 的序列化机制，实现了高效的事件响应与线程安全的逻辑处理。虽然有两个线程处理事件，但任务逻辑（&lt;code&gt;print1&lt;/code&gt;/&lt;code&gt;print2&lt;/code&gt;）本质上是单线程化的，因此更准确地说，这是多线程协作处理事件循环，但任务执行是序列化的。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;&lt;code&gt;Lambda&lt;/code&gt; 的捕获方式 [&amp;amp;]&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;[&amp;amp;] 表示以引用方式捕获所有外部变量。&lt;br /&gt;
在 &lt;code&gt;Lambda&lt;/code&gt; 内部可以直接访问外部作用域的所有变量（如 &lt;code&gt;io&lt;/code&gt;），且操作的是原变量本身，而非副本。&lt;/li&gt;
&lt;li&gt;​对比其他捕获方式：&lt;br /&gt;
[=]：以值方式捕获（创建副本，可能影响性能）。&lt;br /&gt;
[io]：仅捕获 io 变量（需显式指定）。&lt;br /&gt;
此处 [&amp;amp;] 简化了代码，但需确保 &lt;code&gt;Lambda&lt;/code&gt; 生命周期内外部变量有效。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;代码的多线程机制&lt;br /&gt;
&lt;strong&gt;​线程数量与任务类型&lt;/strong&gt;&lt;br /&gt;
代码中通过 &lt;code&gt;std::thread t([&amp;amp;]&amp;#123; io.run(); &amp;#125;)&lt;/code&gt; 创建了一个工作线程，主线程也调用 &lt;code&gt;io.run()&lt;/code&gt;，因此 ​总共有两个线程运行 &lt;code&gt;io_context&lt;/code&gt; 的事件循环。这两个线程会并行处理 &lt;code&gt;io_context&lt;/code&gt; 中的异步操作（如定时器到期事件）。&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;strong&gt;​异步操作的并行性&lt;/strong&gt;&lt;br /&gt;
&lt;code&gt;timer1_&lt;/code&gt; 和 &lt;code&gt;timer2_&lt;/code&gt; 是独立的定时器，它们的异步等待操作会被提交到 &lt;code&gt;io_context&lt;/code&gt; 的任务队列中。理论上，这两个定时器的到期事件可能被分配到不同的线程处理。但由于绑定了 &lt;code&gt;strand_&lt;/code&gt;，所有回调会被强制序列化执行，​实际表现为单线程顺序处理​。&lt;/p&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;Strand 的核心作用&lt;br /&gt;
&lt;strong&gt;​线程安全与顺序保证&lt;/strong&gt;&lt;br /&gt;
&lt;code&gt;strand_ &lt;/code&gt;是 &lt;code&gt;Boost.Asio&lt;/code&gt; 提供的一种隐式同步机制，其作用包括：&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;​序列化回调执行：所有通过 &lt;code&gt;strand_&lt;/code&gt; 提交的回调（如 &lt;code&gt;print1&lt;/code&gt; 和 &lt;code&gt;print2&lt;/code&gt;）会按提交顺序依次执行，即使多个线程在运行 &lt;code&gt;io_context&lt;/code&gt;。&lt;br /&gt;
​消除数据竞争：对共享资源 &lt;code&gt;count_&lt;/code&gt; 的修改（如&lt;code&gt;++count_&lt;/code&gt;）会被限制在同一个线程上下文中，无需显式加锁。&lt;br /&gt;
&lt;strong&gt;​代码中的具体实现&lt;/strong&gt;&lt;/p&gt;
&lt;pre class=&#34;highlight&#34;&gt;&lt;code class=&#34;cpp&#34;&gt;timer1_.&lt;span class=&#34;hljs-built_in&#34;&gt;async_wait&lt;/span&gt;(boost::asio::&lt;span class=&#34;hljs-built_in&#34;&gt;bind_executor&lt;/span&gt;(strand_, ...));
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;将定时器的回调函数绑定到 &lt;code&gt;strand_&lt;/code&gt; 的执行器上，确保回调在 &lt;code&gt;strand_ &lt;/code&gt;的调度下运行。因此，即使两个定时器的到期事件被不同线程触发，&lt;code&gt;print1&lt;/code&gt; 和 &lt;code&gt;print2&lt;/code&gt; 也不会并发执行。&lt;/p&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;执行流程示例&lt;br /&gt;
假设两个定时器同时到期：
&lt;ol&gt;
&lt;li&gt;​事件触发：&lt;code&gt;timer1_&lt;/code&gt; 和 &lt;code&gt;timer2_&lt;/code&gt; 的到期事件被提交到 &lt;code&gt;io_context&lt;/code&gt;。&lt;/li&gt;
&lt;li&gt;​线程分配：事件可能被主线程或工作线程 &lt;code&gt;t&lt;/code&gt; 处理。&lt;/li&gt;
&lt;li&gt;​Strand 调度：无论哪个线程处理事件，回调函数会被 &lt;code&gt;strand_ &lt;/code&gt;序列化。例如：
&lt;ul&gt;
&lt;li&gt;线程1执行 &lt;code&gt;print1&lt;/code&gt; → 输出 &lt;code&gt;Timer 1: 0&lt;/code&gt;。&lt;/li&gt;
&lt;li&gt;线程2执行 &lt;code&gt;print2&lt;/code&gt; → 但需等待 &lt;code&gt;print1&lt;/code&gt; 完成后才能执行，输出 &lt;code&gt;Timer 2: 1&lt;/code&gt;。&lt;/li&gt;
&lt;li&gt;最终 &lt;code&gt;count_&lt;/code&gt; 会严格递增至10，无并发问题&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h1 id=&#34;tcp&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#tcp&#34;&gt;&lt;/a&gt; TCP&lt;/h1&gt;
&lt;p&gt;&lt;strong&gt;TCP连接&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;TCP连接是面向连接的，可靠的，基于字节流的传输层通信协议。&lt;/li&gt;
&lt;li&gt;TCP连接需要三次握手来建立连接，四次挥手来关闭连接。&lt;/li&gt;
&lt;li&gt;TCP连接的建立和关闭都需要消耗一定的资源，因此需要合理管理TCP连接。&lt;/li&gt;
&lt;li&gt;TCP连接的建立和关闭都需要消耗一定的资源，因此需要合理管理TCP连接。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;UDP连接&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;UDP连接是无连接的，不可靠的，基于数据报的传输层通信协议。&lt;/li&gt;
&lt;li&gt;UDP连接不需要建立连接，只需要发送数据报即可。&lt;/li&gt;
&lt;li&gt;UDP连接不需要关闭连接，只需要发送数据报即可。&lt;/li&gt;
&lt;li&gt;UDP连接的建立和关闭不需要消耗资源，因此不需要管理UDP连接。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;TCP和UDP的区别&lt;/strong&gt;&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;TCP&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;UDP&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;面向连接&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;无连接&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;可靠&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;不可靠&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;基于字节流&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;基于数据报&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;需要三次握手&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;不需要握手&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;需要四次挥手&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;不需要挥手&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;建立和关闭连接需要消耗资源&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;建立和关闭连接不需要消耗资源&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;需要管理连接&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;不需要管理连接&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;&lt;strong&gt;TCP和UDP的应用场景&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;TCP连接适用于需要可靠传输的场景，如文件传输、邮件发送等。&lt;/li&gt;
&lt;li&gt;UDP连接适用于需要快速传输的场景，如视频直播、实时游戏等。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;TCP和UDP的编程模型&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;TCP连接的编程模型通常包括客户端和服务端两部分，客户端通过 &lt;code&gt;socket&lt;/code&gt; 函数创建一个套接字，然后通过 &lt;code&gt;connect&lt;/code&gt; 函数连接到服务端，然后通过 &lt;code&gt;send&lt;/code&gt; 和 &lt;code&gt;recv&lt;/code&gt; 函数进行数据的发送和接收，最后通过 &lt;code&gt;close&lt;/code&gt; 函数关闭连接。&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;同步tcp时间服务器&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#同步tcp时间服务器&#34;&gt;&lt;/a&gt; 同步TCP时间服务器&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;命令行参数&lt;/li&gt;
&lt;/ol&gt;
&lt;pre class=&#34;highlight&#34;&gt;&lt;code class=&#34;cpp&#34;&gt;&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(&lt;span class=&#34;hljs-type&#34;&gt;int&lt;/span&gt; argc, &lt;span class=&#34;hljs-type&#34;&gt;char&lt;/span&gt;* argv[])&lt;/span&gt;&lt;/span&gt;&amp;#123;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;strong&gt;argc（Argument Count）​&lt;/strong&gt;&lt;br /&gt;
表示命令行参数的总数量（包括程序名本身）。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;例如，若用户输入 &lt;code&gt;./myprogram arg1 arg2&lt;/code&gt;，则 &lt;code&gt;argc&lt;/code&gt; 的值为 ​3​（程序名 + 2 个参数）。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;​&lt;strong&gt;argv[]（Argument Vector）​&lt;/strong&gt;&lt;br /&gt;
是一个字符串指针数组，存储所有命令行参数的具体值。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;argv[0]&lt;/code&gt;：程序自身的名称（如 “./myprogram”）。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;argv[1]&lt;/code&gt; ~ &lt;code&gt;argv[argc-1]&lt;/code&gt;：用户输入的其他参数。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;argv[argc]&lt;/code&gt;：固定为 NULL（表示数组结束）。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;示例代码：&lt;/p&gt;
&lt;pre class=&#34;highlight&#34;&gt;&lt;code class=&#34;cpp&#34;&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;stdio.h&amp;gt;&lt;/span&gt;&lt;/span&gt;

&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(&lt;span class=&#34;hljs-type&#34;&gt;int&lt;/span&gt; argc, &lt;span class=&#34;hljs-type&#34;&gt;char&lt;/span&gt;* argv[])&lt;/span&gt; &lt;/span&gt;&amp;#123;
    &lt;span class=&#34;hljs-built_in&#34;&gt;printf&lt;/span&gt;(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;参数总数 argc = %d\n&amp;quot;&lt;/span&gt;, argc);

    &lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; (&lt;span class=&#34;hljs-type&#34;&gt;int&lt;/span&gt; i = &lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;; i &amp;lt; argc; i++) &amp;#123;
        &lt;span class=&#34;hljs-built_in&#34;&gt;printf&lt;/span&gt;(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;argv[%d] = %s\n&amp;quot;&lt;/span&gt;, i, argv[i]);
    &amp;#125;

    &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;运行示例：&lt;/p&gt;
&lt;pre class=&#34;highlight&#34;&gt;&lt;code class=&#34;bash&#34;&gt;./myprogram arg1 arg2 arg3
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;输出：&lt;/p&gt;
&lt;pre class=&#34;highlight&#34;&gt;&lt;code class=&#34;bash&#34;&gt;参数总数 argc = 4
argv[0] = ./myprogram
argv[1] = arg1
argv[2] = arg2
argv[3] = arg3
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;同步TCP服务端&lt;/li&gt;
&lt;/ol&gt;
&lt;blockquote&gt;
&lt;p&gt;服务端: 监听端口 13 ,发送时间数据&lt;/p&gt;
&lt;/blockquote&gt;
&lt;pre class=&#34;highlight&#34;&gt;&lt;code class=&#34;cpp&#34;&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;ctime&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;iostream&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;string&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;boost/asio.hpp&amp;gt;&lt;/span&gt;&lt;/span&gt;

&lt;span class=&#34;hljs-keyword&#34;&gt;using&lt;/span&gt; boost::asio::ip::tcp;

&lt;span class=&#34;hljs-function&#34;&gt;std::string &lt;span class=&#34;hljs-title&#34;&gt;make_daytime_string&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;
    std::&lt;span class=&#34;hljs-type&#34;&gt;time_t&lt;/span&gt; now = std::&lt;span class=&#34;hljs-built_in&#34;&gt;time&lt;/span&gt;(&lt;span class=&#34;hljs-literal&#34;&gt;nullptr&lt;/span&gt;);
    &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; std::&lt;span class=&#34;hljs-built_in&#34;&gt;ctime&lt;/span&gt;(&amp;amp;now); &lt;span class=&#34;hljs-comment&#34;&gt;// 格式示例: &amp;quot;Wed Oct  2 00:00:00 2023\n&amp;quot;&lt;/span&gt;
&amp;#125;

&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;
    &lt;span class=&#34;hljs-keyword&#34;&gt;try&lt;/span&gt; &amp;#123;
        boost::asio::io_context io_context;

        &lt;span class=&#34;hljs-comment&#34;&gt;// 监听端口 13 (需管理员权限) 或改用其他端口如 12345&lt;/span&gt;
        &lt;span class=&#34;hljs-function&#34;&gt;tcp::acceptor &lt;span class=&#34;hljs-title&#34;&gt;acceptor&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(io_context, tcp::endpoint(tcp::v4(), &lt;span class=&#34;hljs-number&#34;&gt;13&lt;/span&gt;))&lt;/span&gt;&lt;/span&gt;;

        std::cout &amp;lt;&amp;lt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;Daytime 服务器启动，监听端口: &amp;quot;&lt;/span&gt; &amp;lt;&amp;lt; acceptor.&lt;span class=&#34;hljs-built_in&#34;&gt;local_endpoint&lt;/span&gt;().&lt;span class=&#34;hljs-built_in&#34;&gt;port&lt;/span&gt;() &amp;lt;&amp;lt; std::endl;

        &lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; (;;) &amp;#123;
            &lt;span class=&#34;hljs-function&#34;&gt;tcp::socket &lt;span class=&#34;hljs-title&#34;&gt;socket&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(io_context)&lt;/span&gt;&lt;/span&gt;;
            acceptor.&lt;span class=&#34;hljs-built_in&#34;&gt;accept&lt;/span&gt;(socket); &lt;span class=&#34;hljs-comment&#34;&gt;// 阻塞等待客户端连接&lt;/span&gt;

            std::cout &amp;lt;&amp;lt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;客户端连接: &amp;quot;&lt;/span&gt; &amp;lt;&amp;lt; socket.&lt;span class=&#34;hljs-built_in&#34;&gt;remote_endpoint&lt;/span&gt;() &amp;lt;&amp;lt; std::endl;

            std::string message = &lt;span class=&#34;hljs-built_in&#34;&gt;make_daytime_string&lt;/span&gt;();
            boost::system::error_code ignored_error;

            &lt;span class=&#34;hljs-comment&#34;&gt;// 发送时间数据后立即关闭连接&lt;/span&gt;
            boost::asio::&lt;span class=&#34;hljs-built_in&#34;&gt;write&lt;/span&gt;(socket, boost::asio::&lt;span class=&#34;hljs-built_in&#34;&gt;buffer&lt;/span&gt;(message), ignored_error);
        &amp;#125;
    &amp;#125; &lt;span class=&#34;hljs-built_in&#34;&gt;catch&lt;/span&gt; (std::exception&amp;amp; e) &amp;#123;
        std::cerr &amp;lt;&amp;lt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;异常: &amp;quot;&lt;/span&gt; &amp;lt;&amp;lt; e.&lt;span class=&#34;hljs-built_in&#34;&gt;what&lt;/span&gt;() &amp;lt;&amp;lt; std::endl;
    &amp;#125;
    &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;同步TCP客户端&lt;/li&gt;
&lt;/ol&gt;
&lt;blockquote&gt;
&lt;p&gt;客户端：连接服务器，发送数据，接收响应，关闭连接。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;strong&gt;整体流程&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;**​初始化 I/O 上下文：**创建 io_context 对象，管理所有 I/O 操作。&lt;/li&gt;
&lt;li&gt;**​解析目标地址：**将用户输入的主机名和服务名转换为具体的网络地址列表。&lt;/li&gt;
&lt;li&gt;**​创建套接字：**准备用于通信的套接字对象。&lt;/li&gt;
&lt;li&gt;**​连接服务器：**按地址列表尝试连接，直到成功或全部失败。&lt;/li&gt;
&lt;/ul&gt;
&lt;pre class=&#34;highlight&#34;&gt;&lt;code class=&#34;cpp&#34;&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;array&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;iostream&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;boost/asio.hpp&amp;gt;&lt;/span&gt;&lt;/span&gt;

&lt;span class=&#34;hljs-comment&#34;&gt;// using导入某个变量到当前作用域 &lt;/span&gt;
&lt;span class=&#34;hljs-keyword&#34;&gt;using&lt;/span&gt; boost::asio::ip::tcp; &lt;span class=&#34;hljs-comment&#34;&gt;// tcp命名空间&lt;/span&gt;

&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(&lt;span class=&#34;hljs-type&#34;&gt;int&lt;/span&gt; argc, &lt;span class=&#34;hljs-type&#34;&gt;char&lt;/span&gt;* argv[])&lt;/span&gt;
&lt;/span&gt;&amp;#123;
  &lt;span class=&#34;hljs-keyword&#34;&gt;try&lt;/span&gt;
  &amp;#123;
    &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; (argc != &lt;span class=&#34;hljs-number&#34;&gt;2&lt;/span&gt;)
    &amp;#123;
      &lt;span class=&#34;hljs-comment&#34;&gt;// std::cerr 通常用于输出错误信息，这些信息不会被重定向到文件或管道，而是直接显示在终端上。&lt;/span&gt;
      std::cerr &amp;lt;&amp;lt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;Usage: client &amp;lt;host&amp;gt;&amp;quot;&lt;/span&gt; &amp;lt;&amp;lt; std::endl;
      &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;;
    &amp;#125;

    boost::asio::io_context io_context;
    &lt;span class=&#34;hljs-comment&#34;&gt;//创建解析器对象，用于将 ​主机名 和 ​服务名/端口号 转换为具体的网络地址（IP + 端口）。&lt;/span&gt;
    &lt;span class=&#34;hljs-function&#34;&gt;tcp::resolver &lt;span class=&#34;hljs-title&#34;&gt;resolver&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(io_context)&lt;/span&gt;&lt;/span&gt;;      &lt;span class=&#34;hljs-comment&#34;&gt;// io_context：绑定到同一个 I/O 上下文，确保解析操作由该上下文管理。&lt;/span&gt;
    tcp::resolver::results_type endpoints =     
      resolver.&lt;span class=&#34;hljs-built_in&#34;&gt;resolve&lt;/span&gt;(argv[&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;], &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;cc&amp;quot;&lt;/span&gt;);       &lt;span class=&#34;hljs-comment&#34;&gt;// 解析用户输入的主机名和服务名，生成可能的网络端点列表。&lt;/span&gt;
    &lt;span class=&#34;hljs-function&#34;&gt;tcp::socket &lt;span class=&#34;hljs-title&#34;&gt;socket&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(io_context)&lt;/span&gt;&lt;/span&gt;;          &lt;span class=&#34;hljs-comment&#34;&gt;// 套接字绑定到同一个 I/O 上下文，确保其操作由该上下文管理。&lt;/span&gt;
    boost::asio::&lt;span class=&#34;hljs-built_in&#34;&gt;connect&lt;/span&gt;(socket, endpoints); &lt;span class=&#34;hljs-comment&#34;&gt;// 尝试连接到服务器。&lt;/span&gt;

    &lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; (;;)
    &amp;#123;
      std::array&amp;lt;&lt;span class=&#34;hljs-type&#34;&gt;char&lt;/span&gt;, 128&amp;gt; buf;
      boost::system::error_code error;

      &lt;span class=&#34;hljs-comment&#34;&gt;// read_some函数用于从TCP连接中读取数据。buffer函数用于创建一个缓冲区，用于存储读取的数据。size_t类型表示读取的字节数。&lt;/span&gt;
      &lt;span class=&#34;hljs-type&#34;&gt;size_t&lt;/span&gt; len = socket.&lt;span class=&#34;hljs-built_in&#34;&gt;read_some&lt;/span&gt;(boost::asio::&lt;span class=&#34;hljs-built_in&#34;&gt;buffer&lt;/span&gt;(buf), error); 

      &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; (error == boost::asio::error::eof) &lt;span class=&#34;hljs-comment&#34;&gt;// eof表示连接已关闭。&lt;/span&gt;
        &lt;span class=&#34;hljs-keyword&#34;&gt;break&lt;/span&gt;; &lt;span class=&#34;hljs-comment&#34;&gt;// Connection closed cleanly by peer.&lt;/span&gt;
      &lt;span class=&#34;hljs-keyword&#34;&gt;else&lt;/span&gt; &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; (error)
        &lt;span class=&#34;hljs-keyword&#34;&gt;throw&lt;/span&gt; boost::system::&lt;span class=&#34;hljs-built_in&#34;&gt;system_error&lt;/span&gt;(error); &lt;span class=&#34;hljs-comment&#34;&gt;// Some other error.&lt;/span&gt;

      std::cout.&lt;span class=&#34;hljs-built_in&#34;&gt;write&lt;/span&gt;(buf.&lt;span class=&#34;hljs-built_in&#34;&gt;data&lt;/span&gt;(), len);&lt;span class=&#34;hljs-comment&#34;&gt;// buf.data()返回缓冲区的指针，len表示读取的字节数。&lt;/span&gt;
    &amp;#125;
  &amp;#125;
  &lt;span class=&#34;hljs-built_in&#34;&gt;catch&lt;/span&gt; (std::exception&amp;amp; e)
  &amp;#123;
    std::cerr &amp;lt;&amp;lt; e.&lt;span class=&#34;hljs-built_in&#34;&gt;what&lt;/span&gt;() &amp;lt;&amp;lt; std::endl;
  &amp;#125;

  &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ol&gt;
&lt;li&gt;&lt;code&gt;boost::asio::io_context io_context;&lt;/code&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;strong&gt;​作用：&lt;/strong&gt; 创建 I/O 上下文对象，管理所有底层 I/O 操作（如网络通信、定时器等）。&lt;br /&gt;
&lt;strong&gt;​原理：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;io_context&lt;/code&gt; 是 &lt;code&gt;Boost.Asio&lt;/code&gt; 的 ​事件循环核心，负责调度和处理异步操作。&lt;br /&gt;
所有异步操作（如连接、读写）都需要通过它执行。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;&lt;code&gt;tcp::resolver resolver(io_context);&lt;/code&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;strong&gt;​作用：&lt;/strong&gt; 创建解析器对象，用于将 ​主机名 和 ​服务名/端口号 转换为具体的网络地址（IP + 端口）。&lt;br /&gt;
&lt;strong&gt;​参数：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;io_context&lt;/code&gt;：绑定到同一个 I/O 上下文，确保解析操作由该上下文管理。&lt;br /&gt;
&lt;strong&gt;​功能：&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;解析器 (&lt;code&gt;resolver&lt;/code&gt;) 支持 &lt;code&gt;DNS&lt;/code&gt; 查询，将域名（如 &lt;code&gt;&amp;quot;example.com&amp;quot;&lt;/code&gt;）解析为 IP 地址。&lt;/li&gt;
&lt;li&gt;将服务名（如 &lt;code&gt;&amp;quot;http&amp;quot;&lt;/code&gt;）解析为端口号（如 &lt;code&gt;80&lt;/code&gt;）。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;&lt;code&gt;tcp::resolver::results_type endpoints = resolver.resolve(argv[1], &amp;quot;cc&amp;quot;);&lt;/code&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;strong&gt;​作用：&lt;/strong&gt; 解析用户输入的主机名和服务名，生成可能的网络端点列表。&lt;br /&gt;
&lt;strong&gt;​参数：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;argv[1]&lt;/code&gt;：命令行输入的主机名（如 &lt;code&gt;&amp;quot;localhost&amp;quot;&lt;/code&gt; 或 &lt;code&gt;&amp;quot;192.168.1.100&amp;quot;&lt;/code&gt;）。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;&amp;quot;cc&amp;quot;&lt;/code&gt;：服务名或端口号。这里可能是自定义的服务名（需系统配置）或直接表示端口号（如 &lt;code&gt;&amp;quot;12345&amp;quot;&lt;/code&gt;）。&lt;br /&gt;
&lt;strong&gt;​返回值：&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;&lt;code&gt;endpoints&lt;/code&gt; 是一个端点列表，包含所有可能的 IP 地址和端口组合（例如 &lt;code&gt;IPv4&lt;/code&gt; 和 &lt;code&gt;IPv6&lt;/code&gt; 地址）。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;&lt;code&gt;tcp::socket socket(io_context);&lt;/code&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;strong&gt;​作用：&lt;/strong&gt; 创建 &lt;code&gt;TCP&lt;/code&gt; 套接字对象，用于与服务器通信。&lt;br /&gt;
&lt;strong&gt;​参数：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;io_context&lt;/code&gt;：套接字绑定到同一个 I/O 上下文，确保其操作由该上下文管理。&lt;br /&gt;
&lt;strong&gt;​功能：&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;套接字是网络通信的端点，通过它可以发送和接收数据。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;&lt;code&gt;boost::asio::connect(socket, endpoints);&lt;/code&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;strong&gt;​作用：&lt;/strong&gt; 尝试连接到服务器。&lt;br /&gt;
&lt;strong&gt;​参数：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;socket&lt;/code&gt;：上一步创建的套接字。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;endpoints&lt;/code&gt;：解析得到的端点列表。&lt;br /&gt;
&lt;strong&gt;​行为：&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;按顺序尝试连接 &lt;code&gt;endpoints&lt;/code&gt; 中的每一个端点（如 &lt;code&gt;IPv4&lt;/code&gt; 地址优先，失败后尝试 &lt;code&gt;IPv6&lt;/code&gt;）。&lt;/li&gt;
&lt;li&gt;当某个端点连接成功时，停止尝试。&lt;/li&gt;
&lt;li&gt;如果所有端点均连接失败，抛出异常。&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;异步tcp时间服务器&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#异步tcp时间服务器&#34;&gt;&lt;/a&gt; 异步TCP时间服务器&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;&lt;strong&gt;主函数入口&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre class=&#34;highlight&#34;&gt;&lt;code class=&#34;cpp&#34;&gt;&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt;
&lt;/span&gt;&amp;#123;
  &lt;span class=&#34;hljs-keyword&#34;&gt;try&lt;/span&gt;
  &amp;#123;
    boost::asio::io_context io_context;      &lt;span class=&#34;hljs-comment&#34;&gt;// 创建IO上下文，管理所有异步操作&lt;/span&gt;
    &lt;span class=&#34;hljs-function&#34;&gt;tcp_server &lt;span class=&#34;hljs-title&#34;&gt;server&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(io_context)&lt;/span&gt;&lt;/span&gt;;          &lt;span class=&#34;hljs-comment&#34;&gt;// 创建TCP服务器实例，初始化监听&lt;/span&gt;
    io_context.&lt;span class=&#34;hljs-built_in&#34;&gt;run&lt;/span&gt;();                       &lt;span class=&#34;hljs-comment&#34;&gt;// 启动事件循环，处理异步操作&lt;/span&gt;
  &amp;#125;
  &lt;span class=&#34;hljs-built_in&#34;&gt;catch&lt;/span&gt; (std::exception&amp;amp; e)                 &lt;span class=&#34;hljs-comment&#34;&gt;// 异常处理&lt;/span&gt;
  &amp;#123;
    std::cerr &amp;lt;&amp;lt; e.&lt;span class=&#34;hljs-built_in&#34;&gt;what&lt;/span&gt;() &amp;lt;&amp;lt; std::endl;
  &amp;#125;
  &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;io_context&lt;/code&gt; 是&lt;code&gt;Boost.Asio&lt;/code&gt;的核心，负责调度异步任务。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;tcp_server&lt;/code&gt; 初始化时会开始监听连接。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;io_context.run()&lt;/code&gt; 会阻塞主线程，持续处理异步事件，直到所有任务完成。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;&lt;strong&gt;​TCP服务器初始化（tcp_server构造函数）​&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre class=&#34;highlight&#34;&gt;&lt;code class=&#34;cpp&#34;&gt;&lt;span class=&#34;hljs-built_in&#34;&gt;tcp_server&lt;/span&gt;(boost::asio::io_context&amp;amp; io_context)
  : &lt;span class=&#34;hljs-built_in&#34;&gt;io_context_&lt;/span&gt;(io_context),
    &lt;span class=&#34;hljs-built_in&#34;&gt;acceptor_&lt;/span&gt;(io_context, tcp::&lt;span class=&#34;hljs-built_in&#34;&gt;endpoint&lt;/span&gt;(tcp::&lt;span class=&#34;hljs-built_in&#34;&gt;v4&lt;/span&gt;(), &lt;span class=&#34;hljs-number&#34;&gt;13&lt;/span&gt;)) &lt;span class=&#34;hljs-comment&#34;&gt;// 绑定IPv4地址的13端口&lt;/span&gt;
&amp;#123;
  &lt;span class=&#34;hljs-built_in&#34;&gt;start_accept&lt;/span&gt;(); &lt;span class=&#34;hljs-comment&#34;&gt;// 开始异步等待客户端连接&lt;/span&gt;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;acceptor_&lt;/code&gt; 初始化时绑定到本地13端口。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;start_accept()&lt;/code&gt; 启动异步接受连接的过程。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;&lt;strong&gt;异步接受连接（start_accept）​&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre class=&#34;highlight&#34;&gt;&lt;code class=&#34;cpp&#34;&gt;&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;start_accept&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt;
&lt;/span&gt;&amp;#123;
  tcp_connection::pointer new_connection = tcp_connection::&lt;span class=&#34;hljs-built_in&#34;&gt;create&lt;/span&gt;(io_context_); &lt;span class=&#34;hljs-comment&#34;&gt;// 创建新连接对象&lt;/span&gt;
  acceptor_.&lt;span class=&#34;hljs-built_in&#34;&gt;async_accept&lt;/span&gt;(                       &lt;span class=&#34;hljs-comment&#34;&gt;// 异步接受连接&lt;/span&gt;
      new_connection-&amp;gt;&lt;span class=&#34;hljs-built_in&#34;&gt;socket&lt;/span&gt;(),
      [&lt;span class=&#34;hljs-keyword&#34;&gt;this&lt;/span&gt;, new_connection](&lt;span class=&#34;hljs-type&#34;&gt;const&lt;/span&gt; boost::system::error_code&amp;amp; error) &amp;#123;
          &lt;span class=&#34;hljs-built_in&#34;&gt;handle_accept&lt;/span&gt;(error, new_connection); &lt;span class=&#34;hljs-comment&#34;&gt;// 连接完成时调用处理函数&lt;/span&gt;
      &amp;#125;);
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;tcp_connection::create&lt;/code&gt; 创建新的连接对象，其&lt;code&gt;socket&lt;/code&gt;由&lt;code&gt;io_context&lt;/code&gt;管理。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;async_accept&lt;/code&gt; 异步等待客户端连接。当有连接到来时，&lt;code&gt;lambda&lt;/code&gt;被调用，传递错误码和连接对象。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;&lt;strong&gt;处理新连接（handle_accept）​&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre class=&#34;highlight&#34;&gt;&lt;code class=&#34;cpp&#34;&gt;&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;handle_accept&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(&lt;span class=&#34;hljs-type&#34;&gt;const&lt;/span&gt; boost::system::error_code&amp;amp; error, tcp_connection::pointer new_connection)&lt;/span&gt;
&lt;/span&gt;&amp;#123;
  &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; (!error)
  &amp;#123;
    new_connection-&amp;gt;&lt;span class=&#34;hljs-built_in&#34;&gt;start&lt;/span&gt;(); &lt;span class=&#34;hljs-comment&#34;&gt;// 启动数据发送流程&lt;/span&gt;
  &amp;#125;
  &lt;span class=&#34;hljs-built_in&#34;&gt;start_accept&lt;/span&gt;(); &lt;span class=&#34;hljs-comment&#34;&gt;// 继续监听下一个连接&lt;/span&gt;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;如果没有错误，调用&lt;code&gt;new_connection-&amp;gt;start()&lt;/code&gt;开始处理客户端请求。&lt;/li&gt;
&lt;li&gt;无论是否出错，再次调用&lt;code&gt;start_accept()&lt;/code&gt;，形成循环监听。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;&lt;strong&gt;TCP连接处理（tcp_connection::start）&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre class=&#34;highlight&#34;&gt;&lt;code class=&#34;cpp&#34;&gt;&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;start&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt;
&lt;/span&gt;&amp;#123;
  message_ = &lt;span class=&#34;hljs-built_in&#34;&gt;make_daytime_string&lt;/span&gt;(); &lt;span class=&#34;hljs-comment&#34;&gt;// 生成当前时间字符串&lt;/span&gt;
  &lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;auto&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;self&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(shared_from_this())&lt;/span&gt;&lt;/span&gt;;    &lt;span class=&#34;hljs-comment&#34;&gt;// 获取shared_ptr，延长对象生命周期&lt;/span&gt;
  boost::asio::&lt;span class=&#34;hljs-built_in&#34;&gt;async_write&lt;/span&gt;(         &lt;span class=&#34;hljs-comment&#34;&gt;// 异步发送数据&lt;/span&gt;
      socket_,
      boost::asio::&lt;span class=&#34;hljs-built_in&#34;&gt;buffer&lt;/span&gt;(message_),
      [&lt;span class=&#34;hljs-keyword&#34;&gt;this&lt;/span&gt;, self](&lt;span class=&#34;hljs-type&#34;&gt;const&lt;/span&gt; &lt;span class=&#34;hljs-keyword&#34;&gt;auto&lt;/span&gt;&amp;amp; error, &lt;span class=&#34;hljs-type&#34;&gt;size_t&lt;/span&gt; bytes) &amp;#123;
          &lt;span class=&#34;hljs-built_in&#34;&gt;handle_write&lt;/span&gt;(error, bytes); &lt;span class=&#34;hljs-comment&#34;&gt;// 发送完成后的回调&lt;/span&gt;
      &amp;#125;);
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;make_daytime_string()&lt;/code&gt; 生成当前时间的字符串。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;shared_from_this()&lt;/code&gt; 确保在异步操作期间对象不会被销毁。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;async_write&lt;/code&gt; 异步发送数据，完成后调用&lt;code&gt;handle_write&lt;/code&gt;。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;6&#34;&gt;
&lt;li&gt;&lt;strong&gt;数据发送完成处理（handle_write）​&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre class=&#34;highlight&#34;&gt;&lt;code class=&#34;cpp&#34;&gt;&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;handle_write&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(&lt;span class=&#34;hljs-type&#34;&gt;const&lt;/span&gt; boost::system::error_code&amp;amp; &lt;span class=&#34;hljs-comment&#34;&gt;/*error*/&lt;/span&gt;, &lt;span class=&#34;hljs-type&#34;&gt;size_t&lt;/span&gt; &lt;span class=&#34;hljs-comment&#34;&gt;/*bytes_transferred*/&lt;/span&gt;)&lt;/span&gt;
&lt;/span&gt;&amp;#123;
  &lt;span class=&#34;hljs-comment&#34;&gt;// 此处可添加发送完成后的逻辑，例如关闭连接&lt;/span&gt;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;当前代码未处理发送结果，但可在此处添加错误处理或资源释放逻辑。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;7&#34;&gt;
&lt;li&gt;&lt;strong&gt;生成时间字符串（make_daytime_string）​&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;pre class=&#34;highlight&#34;&gt;&lt;code class=&#34;cpp&#34;&gt;&lt;span class=&#34;hljs-function&#34;&gt;std::string &lt;span class=&#34;hljs-title&#34;&gt;make_daytime_string&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt;
&lt;/span&gt;&amp;#123;
  &lt;span class=&#34;hljs-type&#34;&gt;time_t&lt;/span&gt; now = &lt;span class=&#34;hljs-built_in&#34;&gt;time&lt;/span&gt;(&lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;);
  &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;hljs-built_in&#34;&gt;ctime&lt;/span&gt;(&amp;amp;now); &lt;span class=&#34;hljs-comment&#34;&gt;// 示例输出：&amp;quot;Wed May 22 15:42:36 2024\n&amp;quot;&lt;/span&gt;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;返回的字符串末尾包含换行符，符合Daytime协议标准。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;异步执行流程总结：​&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;服务器启动，监听端口13。&lt;/li&gt;
&lt;li&gt;当客户端连接时，async_accept 完成，触发 handle_accept。&lt;/li&gt;
&lt;li&gt;无错误则调用 start() 发送时间数据。&lt;/li&gt;
&lt;li&gt;数据发送完成后，由 handle_write 处理后续逻辑（当前为空）。&lt;/li&gt;
&lt;li&gt;服务器循环调用 start_accept，持续监听新连接。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;**关键点：**​&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;​生命周期管理：&lt;/strong&gt; 通过 &lt;code&gt;shared_from_this()&lt;/code&gt; 和 &lt;code&gt;shared_ptr&lt;/code&gt; 确保异步操作期间对象存活。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;​异步链式调用：&lt;/strong&gt; &lt;code&gt;async_accept&lt;/code&gt; →&lt;code&gt; handle_accept&lt;/code&gt; → &lt;code&gt;async_write&lt;/code&gt; → &lt;code&gt;handle_write&lt;/code&gt; 形成异步链。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;​端口重用：&lt;/strong&gt; Daytime协议使用13端口，需确保权限允许（Linux/Mac可能需要sudo运行）。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;完整代码：&lt;/strong&gt;&lt;/p&gt;
&lt;pre class=&#34;highlight&#34;&gt;&lt;code class=&#34;cpp&#34;&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;ctime&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;functional&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;iostream&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;memory&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;string&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;boost/asio.hpp&amp;gt;&lt;/span&gt;&lt;/span&gt;

&lt;span class=&#34;hljs-keyword&#34;&gt;using&lt;/span&gt; boost::asio::ip::tcp;

&lt;span class=&#34;hljs-function&#34;&gt;std::string &lt;span class=&#34;hljs-title&#34;&gt;make_daytime_string&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt;
&lt;/span&gt;&amp;#123;
  &lt;span class=&#34;hljs-type&#34;&gt;time_t&lt;/span&gt; now = &lt;span class=&#34;hljs-built_in&#34;&gt;time&lt;/span&gt;(&lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;);
  &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;hljs-built_in&#34;&gt;ctime&lt;/span&gt;(&amp;amp;now); &lt;span class=&#34;hljs-comment&#34;&gt;// 示例输出：&amp;quot;Wed May 22 15:42:36 2024\n&amp;quot;&lt;/span&gt;
&amp;#125;

&lt;span class=&#34;hljs-keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;hljs-title class_&#34;&gt;tcp_connection&lt;/span&gt;
  : &lt;span class=&#34;hljs-keyword&#34;&gt;public&lt;/span&gt; std::enable_shared_from_this&amp;lt;tcp_connection&amp;gt;
&amp;#123;
&lt;span class=&#34;hljs-keyword&#34;&gt;public&lt;/span&gt;:
  &lt;span class=&#34;hljs-keyword&#34;&gt;typedef&lt;/span&gt; std::shared_ptr&amp;lt;tcp_connection&amp;gt; pointer;

  &lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;static&lt;/span&gt; pointer &lt;span class=&#34;hljs-title&#34;&gt;create&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(boost::asio::io_context&amp;amp; io_context)&lt;/span&gt;
  &lt;/span&gt;&amp;#123;
    &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;hljs-built_in&#34;&gt;pointer&lt;/span&gt;(&lt;span class=&#34;hljs-keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;hljs-built_in&#34;&gt;tcp_connection&lt;/span&gt;(io_context));
  &amp;#125;

  &lt;span class=&#34;hljs-function&#34;&gt;tcp::socket&amp;amp; &lt;span class=&#34;hljs-title&#34;&gt;socket&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt;
  &lt;/span&gt;&amp;#123;
    &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; socket_;
  &amp;#125;

  &lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;start&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt;
  &lt;/span&gt;&amp;#123;
    message_ = &lt;span class=&#34;hljs-built_in&#34;&gt;make_daytime_string&lt;/span&gt;(); &lt;span class=&#34;hljs-comment&#34;&gt;// 生成当前时间字符串&lt;/span&gt;
    &lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;auto&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;self&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(shared_from_this())&lt;/span&gt;&lt;/span&gt;;    &lt;span class=&#34;hljs-comment&#34;&gt;// 获取shared_ptr，延长对象生命周期&lt;/span&gt;
    boost::asio::&lt;span class=&#34;hljs-built_in&#34;&gt;async_write&lt;/span&gt;(         &lt;span class=&#34;hljs-comment&#34;&gt;// 异步发送数据&lt;/span&gt;
        socket_,
        boost::asio::&lt;span class=&#34;hljs-built_in&#34;&gt;buffer&lt;/span&gt;(message_),
        [&lt;span class=&#34;hljs-keyword&#34;&gt;this&lt;/span&gt;, self](&lt;span class=&#34;hljs-type&#34;&gt;const&lt;/span&gt; &lt;span class=&#34;hljs-keyword&#34;&gt;auto&lt;/span&gt;&amp;amp; error, &lt;span class=&#34;hljs-type&#34;&gt;size_t&lt;/span&gt; bytes) &amp;#123;
            &lt;span class=&#34;hljs-built_in&#34;&gt;handle_write&lt;/span&gt;(error, bytes); &lt;span class=&#34;hljs-comment&#34;&gt;// 发送完成后的回调&lt;/span&gt;
        &amp;#125;);
  &amp;#125;

&lt;span class=&#34;hljs-keyword&#34;&gt;private&lt;/span&gt;:
  &lt;span class=&#34;hljs-built_in&#34;&gt;tcp_connection&lt;/span&gt;(boost::asio::io_context&amp;amp; io_context)
    : &lt;span class=&#34;hljs-built_in&#34;&gt;socket_&lt;/span&gt;(io_context)
  &amp;#123;
  &amp;#125;

  &lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;handle_write&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(&lt;span class=&#34;hljs-type&#34;&gt;const&lt;/span&gt; boost::system::error_code&amp;amp; &lt;span class=&#34;hljs-comment&#34;&gt;/*error*/&lt;/span&gt;, &lt;span class=&#34;hljs-type&#34;&gt;size_t&lt;/span&gt; &lt;span class=&#34;hljs-comment&#34;&gt;/*bytes_transferred*/&lt;/span&gt;)&lt;/span&gt;
  &lt;/span&gt;&amp;#123;
    &lt;span class=&#34;hljs-comment&#34;&gt;// 此处可添加发送完成后的逻辑，例如关闭连接&lt;/span&gt;
  &amp;#125;

  tcp::socket socket_;
  std::string message_;
&amp;#125;;

&lt;span class=&#34;hljs-keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;hljs-title class_&#34;&gt;tcp_server&lt;/span&gt;
&amp;#123;
&lt;span class=&#34;hljs-keyword&#34;&gt;public&lt;/span&gt;:
  &lt;span class=&#34;hljs-built_in&#34;&gt;tcp_server&lt;/span&gt;(boost::asio::io_context&amp;amp; io_context)
    :&lt;span class=&#34;hljs-built_in&#34;&gt;io_context_&lt;/span&gt;(io_context),
    &lt;span class=&#34;hljs-built_in&#34;&gt;acceptor_&lt;/span&gt;(io_context, tcp::&lt;span class=&#34;hljs-built_in&#34;&gt;endpoint&lt;/span&gt;(tcp::&lt;span class=&#34;hljs-built_in&#34;&gt;v4&lt;/span&gt;(), &lt;span class=&#34;hljs-number&#34;&gt;13&lt;/span&gt;)) &lt;span class=&#34;hljs-comment&#34;&gt;// 绑定IPv4地址的13端口&lt;/span&gt;
  &amp;#123;
    &lt;span class=&#34;hljs-built_in&#34;&gt;start_accept&lt;/span&gt;(); &lt;span class=&#34;hljs-comment&#34;&gt;// 开始异步等待客户端连接&lt;/span&gt;
  &amp;#125;

&lt;span class=&#34;hljs-keyword&#34;&gt;private&lt;/span&gt;:
  &lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;start_accept&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;
    tcp_connection::pointer new_connection = tcp_connection::&lt;span class=&#34;hljs-built_in&#34;&gt;create&lt;/span&gt;(io_context_);&lt;span class=&#34;hljs-comment&#34;&gt;// 创建新连接对象&lt;/span&gt;
    acceptor_.&lt;span class=&#34;hljs-built_in&#34;&gt;async_accept&lt;/span&gt;(         &lt;span class=&#34;hljs-comment&#34;&gt;// 异步接受连接&lt;/span&gt;
        new_connection-&amp;gt;&lt;span class=&#34;hljs-built_in&#34;&gt;socket&lt;/span&gt;(),
        [&lt;span class=&#34;hljs-keyword&#34;&gt;this&lt;/span&gt;, new_connection](&lt;span class=&#34;hljs-type&#34;&gt;const&lt;/span&gt; boost::system::error_code&amp;amp; error) &amp;#123;
            &lt;span class=&#34;hljs-comment&#34;&gt;// 这里的 this 指向当前 tcp_server 对象&lt;/span&gt;
            &lt;span class=&#34;hljs-built_in&#34;&gt;handle_accept&lt;/span&gt;(error, new_connection);
        &amp;#125;
    );
  &amp;#125; 

  &lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;handle_accept&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(&lt;span class=&#34;hljs-type&#34;&gt;const&lt;/span&gt; boost::system::error_code&amp;amp; error, tcp_connection::pointer new_connection)&lt;/span&gt;
  &lt;/span&gt;&amp;#123;
    &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; (!error)
    &amp;#123;
      new_connection-&amp;gt;&lt;span class=&#34;hljs-built_in&#34;&gt;start&lt;/span&gt;(); &lt;span class=&#34;hljs-comment&#34;&gt;// 启动数据发送流程&lt;/span&gt;
    &amp;#125;
    &lt;span class=&#34;hljs-built_in&#34;&gt;start_accept&lt;/span&gt;(); &lt;span class=&#34;hljs-comment&#34;&gt;// 继续监听下一个连接&lt;/span&gt;
  &amp;#125;

  boost::asio::io_context&amp;amp; io_context_;
  tcp::acceptor acceptor_;
&amp;#125;;

&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt;
&lt;/span&gt;&amp;#123;
  &lt;span class=&#34;hljs-keyword&#34;&gt;try&lt;/span&gt;
  &amp;#123;
    boost::asio::io_context io_context;      &lt;span class=&#34;hljs-comment&#34;&gt;// 创建IO上下文，管理所有异步操作&lt;/span&gt;
    &lt;span class=&#34;hljs-function&#34;&gt;tcp_server &lt;span class=&#34;hljs-title&#34;&gt;server&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(io_context)&lt;/span&gt;&lt;/span&gt;;          &lt;span class=&#34;hljs-comment&#34;&gt;// 创建TCP服务器实例，初始化监听&lt;/span&gt;
    io_context.&lt;span class=&#34;hljs-built_in&#34;&gt;run&lt;/span&gt;();                       &lt;span class=&#34;hljs-comment&#34;&gt;// 启动事件循环，处理异步操作&lt;/span&gt;
  &amp;#125;
  &lt;span class=&#34;hljs-built_in&#34;&gt;catch&lt;/span&gt; (std::exception&amp;amp; e)                 &lt;span class=&#34;hljs-comment&#34;&gt;// 异常处理&lt;/span&gt;
  &amp;#123;
    std::cerr &amp;lt;&amp;lt; e.&lt;span class=&#34;hljs-built_in&#34;&gt;what&lt;/span&gt;() &amp;lt;&amp;lt; std::endl;
  &amp;#125;
  &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h1 id=&#34;upd&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#upd&#34;&gt;&lt;/a&gt; UPD&lt;/h1&gt;
&lt;h2 id=&#34;同步udp客户端&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#同步udp客户端&#34;&gt;&lt;/a&gt; 同步UDP客户端&lt;/h2&gt;
&lt;pre class=&#34;highlight&#34;&gt;&lt;code class=&#34;cpp&#34;&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;array&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;iostream&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;boost/asio.hpp&amp;gt;&lt;/span&gt;&lt;/span&gt;

&lt;span class=&#34;hljs-keyword&#34;&gt;using&lt;/span&gt; boost::asio::ip::udp;

&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(&lt;span class=&#34;hljs-type&#34;&gt;int&lt;/span&gt; argc, &lt;span class=&#34;hljs-type&#34;&gt;char&lt;/span&gt;* argv[])&lt;/span&gt;
&lt;/span&gt;&amp;#123;
  &lt;span class=&#34;hljs-keyword&#34;&gt;try&lt;/span&gt;
  &amp;#123;
    &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; (argc != &lt;span class=&#34;hljs-number&#34;&gt;2&lt;/span&gt;)
    &amp;#123;
      std::cerr &amp;lt;&amp;lt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;Usage: client &amp;lt;host&amp;gt;&amp;quot;&lt;/span&gt; &amp;lt;&amp;lt; std::endl;
      &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;;
    &amp;#125;

    boost::asio::io_context io_context;

    &lt;span class=&#34;hljs-function&#34;&gt;udp::resolver &lt;span class=&#34;hljs-title&#34;&gt;resolver&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(io_context)&lt;/span&gt;&lt;/span&gt;;
    udp::endpoint receiver_endpoint =
      *resolver.&lt;span class=&#34;hljs-built_in&#34;&gt;resolve&lt;/span&gt;(udp::&lt;span class=&#34;hljs-built_in&#34;&gt;v4&lt;/span&gt;(), argv[&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;], &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;daytime&amp;quot;&lt;/span&gt;).&lt;span class=&#34;hljs-built_in&#34;&gt;begin&lt;/span&gt;();

    &lt;span class=&#34;hljs-function&#34;&gt;udp::socket &lt;span class=&#34;hljs-title&#34;&gt;socket&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(io_context)&lt;/span&gt;&lt;/span&gt;;
    socket.&lt;span class=&#34;hljs-built_in&#34;&gt;open&lt;/span&gt;(udp::&lt;span class=&#34;hljs-built_in&#34;&gt;v4&lt;/span&gt;());

    std::array&amp;lt;&lt;span class=&#34;hljs-type&#34;&gt;char&lt;/span&gt;, 1&amp;gt; send_buf  = &amp;lt;!--swig￼&lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;--&amp;gt;;
    socket.&lt;span class=&#34;hljs-built_in&#34;&gt;send_to&lt;/span&gt;(boost::asio::&lt;span class=&#34;hljs-built_in&#34;&gt;buffer&lt;/span&gt;(send_buf), receiver_endpoint);

    std::array&amp;lt;&lt;span class=&#34;hljs-type&#34;&gt;char&lt;/span&gt;, 128&amp;gt; recv_buf;
    udp::endpoint sender_endpoint;
    &lt;span class=&#34;hljs-type&#34;&gt;size_t&lt;/span&gt; len = socket.&lt;span class=&#34;hljs-built_in&#34;&gt;receive_from&lt;/span&gt;(
        boost::asio::&lt;span class=&#34;hljs-built_in&#34;&gt;buffer&lt;/span&gt;(recv_buf), sender_endpoint);

    std::cout.&lt;span class=&#34;hljs-built_in&#34;&gt;write&lt;/span&gt;(recv_buf.&lt;span class=&#34;hljs-built_in&#34;&gt;data&lt;/span&gt;(), len);
  &amp;#125;
  &lt;span class=&#34;hljs-built_in&#34;&gt;catch&lt;/span&gt; (std::exception&amp;amp; e)
  &amp;#123;
    std::cerr &amp;lt;&amp;lt; e.&lt;span class=&#34;hljs-built_in&#34;&gt;what&lt;/span&gt;() &amp;lt;&amp;lt; std::endl;
  &amp;#125;

  &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;异步udp服务端&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#异步udp服务端&#34;&gt;&lt;/a&gt; 异步UDP服务端&lt;/h2&gt;
&lt;pre class=&#34;highlight&#34;&gt;&lt;code class=&#34;cpp&#34;&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;array&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;ctime&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;functional&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;iostream&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;memory&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;string&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;boost/asio.hpp&amp;gt;&lt;/span&gt;&lt;/span&gt;

&lt;span class=&#34;hljs-keyword&#34;&gt;using&lt;/span&gt; boost::asio::ip::udp;

&lt;span class=&#34;hljs-function&#34;&gt;std::string &lt;span class=&#34;hljs-title&#34;&gt;make_daytime_string&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt;
&lt;/span&gt;&amp;#123;
  &lt;span class=&#34;hljs-keyword&#34;&gt;using&lt;/span&gt; &lt;span class=&#34;hljs-keyword&#34;&gt;namespace&lt;/span&gt; std; &lt;span class=&#34;hljs-comment&#34;&gt;// For time_t, time and ctime;&lt;/span&gt;
  &lt;span class=&#34;hljs-type&#34;&gt;time_t&lt;/span&gt; now = &lt;span class=&#34;hljs-built_in&#34;&gt;time&lt;/span&gt;(&lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;);
  &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;hljs-built_in&#34;&gt;ctime&lt;/span&gt;(&amp;amp;now);
&amp;#125;

&lt;span class=&#34;hljs-keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;hljs-title class_&#34;&gt;udp_server&lt;/span&gt;
&amp;#123;
&lt;span class=&#34;hljs-keyword&#34;&gt;public&lt;/span&gt;:
  &lt;span class=&#34;hljs-built_in&#34;&gt;udp_server&lt;/span&gt;(boost::asio::io_context&amp;amp; io_context)
    : &lt;span class=&#34;hljs-built_in&#34;&gt;socket_&lt;/span&gt;(io_context, udp::&lt;span class=&#34;hljs-built_in&#34;&gt;endpoint&lt;/span&gt;(udp::&lt;span class=&#34;hljs-built_in&#34;&gt;v4&lt;/span&gt;(), &lt;span class=&#34;hljs-number&#34;&gt;13&lt;/span&gt;))
  &amp;#123;
    &lt;span class=&#34;hljs-built_in&#34;&gt;start_receive&lt;/span&gt;();
  &amp;#125;

&lt;span class=&#34;hljs-keyword&#34;&gt;private&lt;/span&gt;:
  &lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;start_receive&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt;
  &lt;/span&gt;&amp;#123;
    socket_.&lt;span class=&#34;hljs-built_in&#34;&gt;async_receive_from&lt;/span&gt;(
        boost::asio::&lt;span class=&#34;hljs-built_in&#34;&gt;buffer&lt;/span&gt;(recv_buffer_), remote_endpoint_,
        std::&lt;span class=&#34;hljs-built_in&#34;&gt;bind&lt;/span&gt;(&amp;amp;udp_server::handle_receive, &lt;span class=&#34;hljs-keyword&#34;&gt;this&lt;/span&gt;,
          boost::asio::placeholders::error,
          boost::asio::placeholders::bytes_transferred));
  &amp;#125;

  &lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;handle_receive&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(&lt;span class=&#34;hljs-type&#34;&gt;const&lt;/span&gt; boost::system::error_code&amp;amp; error,
      std::&lt;span class=&#34;hljs-type&#34;&gt;size_t&lt;/span&gt; &lt;span class=&#34;hljs-comment&#34;&gt;/*bytes_transferred*/&lt;/span&gt;)&lt;/span&gt;
  &lt;/span&gt;&amp;#123;
    &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; (!error)
    &amp;#123;
      &lt;span class=&#34;hljs-function&#34;&gt;std::shared_ptr&amp;lt;std::string&amp;gt; &lt;span class=&#34;hljs-title&#34;&gt;message&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(
          &lt;span class=&#34;hljs-keyword&#34;&gt;new&lt;/span&gt; std::string(make_daytime_string()))&lt;/span&gt;&lt;/span&gt;;

      socket_.&lt;span class=&#34;hljs-built_in&#34;&gt;async_send_to&lt;/span&gt;(boost::asio::&lt;span class=&#34;hljs-built_in&#34;&gt;buffer&lt;/span&gt;(*message), remote_endpoint_,
          std::&lt;span class=&#34;hljs-built_in&#34;&gt;bind&lt;/span&gt;(&amp;amp;udp_server::handle_send, &lt;span class=&#34;hljs-keyword&#34;&gt;this&lt;/span&gt;, message,
            boost::asio::placeholders::error,
            boost::asio::placeholders::bytes_transferred));

      &lt;span class=&#34;hljs-built_in&#34;&gt;start_receive&lt;/span&gt;();
    &amp;#125;
  &amp;#125;

  &lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;handle_send&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(std::shared_ptr&amp;lt;std::string&amp;gt; &lt;span class=&#34;hljs-comment&#34;&gt;/*message*/&lt;/span&gt;,
      &lt;span class=&#34;hljs-type&#34;&gt;const&lt;/span&gt; boost::system::error_code&amp;amp; &lt;span class=&#34;hljs-comment&#34;&gt;/*error*/&lt;/span&gt;,
      std::&lt;span class=&#34;hljs-type&#34;&gt;size_t&lt;/span&gt; &lt;span class=&#34;hljs-comment&#34;&gt;/*bytes_transferred*/&lt;/span&gt;)&lt;/span&gt;
  &lt;/span&gt;&amp;#123;
  &amp;#125;

  udp::socket socket_;
  udp::endpoint remote_endpoint_;
  std::array&amp;lt;&lt;span class=&#34;hljs-type&#34;&gt;char&lt;/span&gt;, 1&amp;gt; recv_buffer_;
&amp;#125;;

&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt;
&lt;/span&gt;&amp;#123;
  &lt;span class=&#34;hljs-keyword&#34;&gt;try&lt;/span&gt;
  &amp;#123;
    boost::asio::io_context io_context;
    &lt;span class=&#34;hljs-function&#34;&gt;udp_server &lt;span class=&#34;hljs-title&#34;&gt;server&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(io_context)&lt;/span&gt;&lt;/span&gt;;
    io_context.&lt;span class=&#34;hljs-built_in&#34;&gt;run&lt;/span&gt;();
  &amp;#125;
  &lt;span class=&#34;hljs-built_in&#34;&gt;catch&lt;/span&gt; (std::exception&amp;amp; e)
  &amp;#123;
    std::cerr &amp;lt;&amp;lt; e.&lt;span class=&#34;hljs-built_in&#34;&gt;what&lt;/span&gt;() &amp;lt;&amp;lt; std::endl;
  &amp;#125;

  &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h1 id=&#34;组合tcpudp&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#组合tcpudp&#34;&gt;&lt;/a&gt; 组合TCP/UDP&lt;/h1&gt;
&lt;pre class=&#34;highlight&#34;&gt;&lt;code class=&#34;cpp&#34;&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;array&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;ctime&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;functional&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;iostream&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;memory&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;string&amp;gt;&lt;/span&gt;&lt;/span&gt;
&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;span class=&#34;hljs-keyword&#34;&gt;include&lt;/span&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;lt;boost/asio.hpp&amp;gt;&lt;/span&gt;&lt;/span&gt;

&lt;span class=&#34;hljs-keyword&#34;&gt;using&lt;/span&gt; boost::asio::ip::tcp;
&lt;span class=&#34;hljs-keyword&#34;&gt;using&lt;/span&gt; boost::asio::ip::udp;

&lt;span class=&#34;hljs-function&#34;&gt;std::string &lt;span class=&#34;hljs-title&#34;&gt;make_daytime_string&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt;
&lt;/span&gt;&amp;#123;
  &lt;span class=&#34;hljs-keyword&#34;&gt;using&lt;/span&gt; &lt;span class=&#34;hljs-keyword&#34;&gt;namespace&lt;/span&gt; std; &lt;span class=&#34;hljs-comment&#34;&gt;// For time_t, time and ctime;&lt;/span&gt;
  &lt;span class=&#34;hljs-type&#34;&gt;time_t&lt;/span&gt; now = &lt;span class=&#34;hljs-built_in&#34;&gt;time&lt;/span&gt;(&lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;);
  &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;hljs-built_in&#34;&gt;ctime&lt;/span&gt;(&amp;amp;now);
&amp;#125;

&lt;span class=&#34;hljs-keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;hljs-title class_&#34;&gt;tcp_connection&lt;/span&gt;
  : &lt;span class=&#34;hljs-keyword&#34;&gt;public&lt;/span&gt; std::enable_shared_from_this&amp;lt;tcp_connection&amp;gt;
&amp;#123;
&lt;span class=&#34;hljs-keyword&#34;&gt;public&lt;/span&gt;:
  &lt;span class=&#34;hljs-keyword&#34;&gt;typedef&lt;/span&gt; std::shared_ptr&amp;lt;tcp_connection&amp;gt; pointer;

  &lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;static&lt;/span&gt; pointer &lt;span class=&#34;hljs-title&#34;&gt;create&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(boost::asio::io_context&amp;amp; io_context)&lt;/span&gt;
  &lt;/span&gt;&amp;#123;
    &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;hljs-built_in&#34;&gt;pointer&lt;/span&gt;(&lt;span class=&#34;hljs-keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;hljs-built_in&#34;&gt;tcp_connection&lt;/span&gt;(io_context));
  &amp;#125;

  &lt;span class=&#34;hljs-function&#34;&gt;tcp::socket&amp;amp; &lt;span class=&#34;hljs-title&#34;&gt;socket&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt;
  &lt;/span&gt;&amp;#123;
    &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; socket_;
  &amp;#125;

  &lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;start&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt;
  &lt;/span&gt;&amp;#123;
    message_ = &lt;span class=&#34;hljs-built_in&#34;&gt;make_daytime_string&lt;/span&gt;();

    boost::asio::&lt;span class=&#34;hljs-built_in&#34;&gt;async_write&lt;/span&gt;(socket_, boost::asio::&lt;span class=&#34;hljs-built_in&#34;&gt;buffer&lt;/span&gt;(message_),
        std::&lt;span class=&#34;hljs-built_in&#34;&gt;bind&lt;/span&gt;(&amp;amp;tcp_connection::handle_write, &lt;span class=&#34;hljs-built_in&#34;&gt;shared_from_this&lt;/span&gt;()));
  &amp;#125;

&lt;span class=&#34;hljs-keyword&#34;&gt;private&lt;/span&gt;:
  &lt;span class=&#34;hljs-built_in&#34;&gt;tcp_connection&lt;/span&gt;(boost::asio::io_context&amp;amp; io_context)
    : &lt;span class=&#34;hljs-built_in&#34;&gt;socket_&lt;/span&gt;(io_context)
  &amp;#123;
  &amp;#125;

  &lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;handle_write&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt;
  &lt;/span&gt;&amp;#123;
  &amp;#125;

  tcp::socket socket_;
  std::string message_;
&amp;#125;;

&lt;span class=&#34;hljs-keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;hljs-title class_&#34;&gt;tcp_server&lt;/span&gt;
&amp;#123;
&lt;span class=&#34;hljs-keyword&#34;&gt;public&lt;/span&gt;:
  &lt;span class=&#34;hljs-built_in&#34;&gt;tcp_server&lt;/span&gt;(boost::asio::io_context&amp;amp; io_context)
    : &lt;span class=&#34;hljs-built_in&#34;&gt;io_context_&lt;/span&gt;(io_context),
      &lt;span class=&#34;hljs-built_in&#34;&gt;acceptor_&lt;/span&gt;(io_context, tcp::&lt;span class=&#34;hljs-built_in&#34;&gt;endpoint&lt;/span&gt;(tcp::&lt;span class=&#34;hljs-built_in&#34;&gt;v4&lt;/span&gt;(), &lt;span class=&#34;hljs-number&#34;&gt;13&lt;/span&gt;))
  &amp;#123;
    &lt;span class=&#34;hljs-built_in&#34;&gt;start_accept&lt;/span&gt;();
  &amp;#125;

&lt;span class=&#34;hljs-keyword&#34;&gt;private&lt;/span&gt;:
  &lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;start_accept&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt;
  &lt;/span&gt;&amp;#123;
    tcp_connection::pointer new_connection =
      tcp_connection::&lt;span class=&#34;hljs-built_in&#34;&gt;create&lt;/span&gt;(io_context_);

    acceptor_.&lt;span class=&#34;hljs-built_in&#34;&gt;async_accept&lt;/span&gt;(new_connection-&amp;gt;&lt;span class=&#34;hljs-built_in&#34;&gt;socket&lt;/span&gt;(),
        std::&lt;span class=&#34;hljs-built_in&#34;&gt;bind&lt;/span&gt;(&amp;amp;tcp_server::handle_accept, &lt;span class=&#34;hljs-keyword&#34;&gt;this&lt;/span&gt;, new_connection,
          boost::asio::placeholders::error));
  &amp;#125;

  &lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;handle_accept&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(tcp_connection::pointer new_connection,
      &lt;span class=&#34;hljs-type&#34;&gt;const&lt;/span&gt; boost::system::error_code&amp;amp; error)&lt;/span&gt;
  &lt;/span&gt;&amp;#123;
    &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; (!error)
    &amp;#123;
      new_connection-&amp;gt;&lt;span class=&#34;hljs-built_in&#34;&gt;start&lt;/span&gt;();
    &amp;#125;

    &lt;span class=&#34;hljs-built_in&#34;&gt;start_accept&lt;/span&gt;();
  &amp;#125;

  boost::asio::io_context&amp;amp; io_context_;
  tcp::acceptor acceptor_;
&amp;#125;;

&lt;span class=&#34;hljs-keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;hljs-title class_&#34;&gt;udp_server&lt;/span&gt;
&amp;#123;
&lt;span class=&#34;hljs-keyword&#34;&gt;public&lt;/span&gt;:
  &lt;span class=&#34;hljs-built_in&#34;&gt;udp_server&lt;/span&gt;(boost::asio::io_context&amp;amp; io_context)
    : &lt;span class=&#34;hljs-built_in&#34;&gt;socket_&lt;/span&gt;(io_context, udp::&lt;span class=&#34;hljs-built_in&#34;&gt;endpoint&lt;/span&gt;(udp::&lt;span class=&#34;hljs-built_in&#34;&gt;v4&lt;/span&gt;(), &lt;span class=&#34;hljs-number&#34;&gt;13&lt;/span&gt;))
  &amp;#123;
    &lt;span class=&#34;hljs-built_in&#34;&gt;start_receive&lt;/span&gt;();
  &amp;#125;

&lt;span class=&#34;hljs-keyword&#34;&gt;private&lt;/span&gt;:
  &lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;start_receive&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt;
  &lt;/span&gt;&amp;#123;
    socket_.&lt;span class=&#34;hljs-built_in&#34;&gt;async_receive_from&lt;/span&gt;(
        boost::asio::&lt;span class=&#34;hljs-built_in&#34;&gt;buffer&lt;/span&gt;(recv_buffer_), remote_endpoint_,
        std::&lt;span class=&#34;hljs-built_in&#34;&gt;bind&lt;/span&gt;(&amp;amp;udp_server::handle_receive, &lt;span class=&#34;hljs-keyword&#34;&gt;this&lt;/span&gt;,
          boost::asio::placeholders::error));
  &amp;#125;

  &lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;handle_receive&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(&lt;span class=&#34;hljs-type&#34;&gt;const&lt;/span&gt; boost::system::error_code&amp;amp; error)&lt;/span&gt;
  &lt;/span&gt;&amp;#123;
    &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; (!error)
    &amp;#123;
      &lt;span class=&#34;hljs-function&#34;&gt;std::shared_ptr&amp;lt;std::string&amp;gt; &lt;span class=&#34;hljs-title&#34;&gt;message&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(
          &lt;span class=&#34;hljs-keyword&#34;&gt;new&lt;/span&gt; std::string(make_daytime_string()))&lt;/span&gt;&lt;/span&gt;;

      socket_.&lt;span class=&#34;hljs-built_in&#34;&gt;async_send_to&lt;/span&gt;(boost::asio::&lt;span class=&#34;hljs-built_in&#34;&gt;buffer&lt;/span&gt;(*message), remote_endpoint_,
          std::&lt;span class=&#34;hljs-built_in&#34;&gt;bind&lt;/span&gt;(&amp;amp;udp_server::handle_send, &lt;span class=&#34;hljs-keyword&#34;&gt;this&lt;/span&gt;, message));

      &lt;span class=&#34;hljs-built_in&#34;&gt;start_receive&lt;/span&gt;();
    &amp;#125;
  &amp;#125;

  &lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;handle_send&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(std::shared_ptr&amp;lt;std::string&amp;gt; &lt;span class=&#34;hljs-comment&#34;&gt;/*message*/&lt;/span&gt;)&lt;/span&gt;
  &lt;/span&gt;&amp;#123;
  &amp;#125;

  udp::socket socket_;
  udp::endpoint remote_endpoint_;
  std::array&amp;lt;&lt;span class=&#34;hljs-type&#34;&gt;char&lt;/span&gt;, 1&amp;gt; recv_buffer_;
&amp;#125;;

&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-type&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;()&lt;/span&gt;
&lt;/span&gt;&amp;#123;
  &lt;span class=&#34;hljs-keyword&#34;&gt;try&lt;/span&gt;
  &amp;#123;
    boost::asio::io_context io_context;
    &lt;span class=&#34;hljs-function&#34;&gt;tcp_server &lt;span class=&#34;hljs-title&#34;&gt;server1&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(io_context)&lt;/span&gt;&lt;/span&gt;;
    &lt;span class=&#34;hljs-function&#34;&gt;udp_server &lt;span class=&#34;hljs-title&#34;&gt;server2&lt;/span&gt;&lt;span class=&#34;hljs-params&#34;&gt;(io_context)&lt;/span&gt;&lt;/span&gt;;
    io_context.&lt;span class=&#34;hljs-built_in&#34;&gt;run&lt;/span&gt;();
  &amp;#125;
  &lt;span class=&#34;hljs-built_in&#34;&gt;catch&lt;/span&gt; (std::exception&amp;amp; e)
  &amp;#123;
    std::cerr &amp;lt;&amp;lt; e.&lt;span class=&#34;hljs-built_in&#34;&gt;what&lt;/span&gt;() &amp;lt;&amp;lt; std::endl;
  &amp;#125;

  &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
